Javascript.validate:
var val = Services.getValue(LQFee.dataBinding);
var err = validateCurrencyValue(val, 99999.99, false);
if( null == err || val < 0 )
{	
	if ( val > 0 || val == 0 )
	{
		var fmVal = WPU.formatToTwoDP(val);
		Services.setValue(LQFee.dataBinding, fmVal);
	}
	else
	{
		// Negative or zero amount entered
		err = ErrorCode.getErrorCode("CaseMan_negativeFeeEntered_Msg");
	}
}
return err;

Javascript.miscCode:
function DefaultCurrency687() {}
DefaultCurrency687.dataBinding = "/ds/EnterVariableData/LQAndHearing/LQFeeCurrency";
DefaultCurrency687.tabIndex = -1;
DefaultCurrency687.maxLength = 3;
DefaultCurrency687.isReadOnly = function(){return true;}
DefaultCurrency687.isTemporary = function(){return true;}
DefaultCurrency687.transformToDisplay = function(value){
	return WPS.__CaseManUtils().transformCurrencySymbolToDisplay(value,null,null); }
DefaultCurrency687.transformToModel = function(value){
	return WPS.__CaseManUtils().transformCurrencySymbolToModel(value,null,null); }
